def kg_coverage(graph, expected_entities: list[str]) -> float:
    """Fraction of expected entities present in the graph."""
    found = 0
    for entity in expected_entities:
        result = graph.query(
            "MATCH (n {id: $id}) RETURN count(n) AS cnt",
            params={"id": entity}
        )
        if result and result[0]["cnt"] > 0:
            found += 1
    return found / len(expected_entities) if expected_entities else 0.0

def kg_avg_degree(graph) -> float:
    """Average number of relationships per entity node."""
    result = graph.query(
        """MATCH (n)
           OPTIONAL MATCH (n)-[r]-()
           RETURN avg(count(r)) AS avg_degree"""
    )
    return result[0]["avg_degree"] if result else 0.0

# Reference check
expected = ["BERT", "GPT", "Transformer", "Jacob Devlin", "Attention Mechanism"]
print(f"Coverage: {kg_coverage(graph, expected):.2f}")
print(f"Avg degree: {kg_avg_degree(graph):.1f}")
